"use client";

/**
 * FilterBar Component
 *
 * Horizontal filter controls with chips for SaaS dashboards.
 * Optimized for Product Mode with efficient filtering interactions.
 *
 * @example
 * ```tsx
 * <FilterBar
 *   filters={[
 *     { key: 'status', label: 'Status', type: 'select', options: statusOptions }
 *   ]}
 *   activeFilters={activeFilters}
 *   onFilterChange={handleFilterChange}
 *   onFilterRemove={handleFilterRemove}
 * />
 * ```
 */

import { forwardRef, useState, useRef, useEffect } from "react";
import { Search, X, ChevronDown, Filter, Calendar } from "lucide-react";
import type {
  FilterBarProps,
  FilterDefinition,
  FilterOption,
} from "./FilterBar.types";
import styles from "./FilterBar.module.css";

// Filter dropdown component
const FilterDropdown = ({
  filter,
  onSelect,
  onClose,
}: {
  filter: FilterDefinition;
  onSelect: (value: string | string[]) => void;
  onClose: () => void;
}) => {
  const [selectedValues, setSelectedValues] = useState<string[]>([]);

  const handleOptionClick = (option: FilterOption) => {
    if (filter.type === "multi-select") {
      const newValues = selectedValues.includes(option.value)
        ? selectedValues.filter((v) => v !== option.value)
        : [...selectedValues, option.value];
      setSelectedValues(newValues);
    } else {
      onSelect(option.value);
      onClose();
    }
  };

  const handleApply = () => {
    if (selectedValues.length > 0) {
      onSelect(selectedValues);
    }
    onClose();
  };

  return (
    <div className={styles.dropdown}>
      {filter.options?.map((option) => (
        <button
          key={option.value}
          type="button"
          className={`${styles.dropdownItem} ${selectedValues.includes(option.value) ? styles.dropdownItemSelected : ""}`}
          onClick={() => handleOptionClick(option)}
        >
          {filter.type === "multi-select" && (
            <span className={styles.checkbox}>
              {selectedValues.includes(option.value) && "✓"}
            </span>
          )}
          <span>{option.label}</span>
          {option.count !== undefined && (
            <span className={styles.optionCount}>{option.count}</span>
          )}
        </button>
      ))}
      {filter.type === "multi-select" && (
        <div className={styles.dropdownFooter}>
          <button
            type="button"
            className={styles.dropdownCancel}
            onClick={onClose}
          >
            Cancel
          </button>
          <button
            type="button"
            className={styles.dropdownApply}
            onClick={handleApply}
          >
            Apply
          </button>
        </div>
      )}
    </div>
  );
};

export const FilterBar = forwardRef<HTMLDivElement, FilterBarProps>(
  (
    {
      filters,
      activeFilters,
      onFilterChange,
      onFilterRemove,
      onClearAll,
      searchable = false,
      searchValue = "",
      onSearchChange,
      searchPlaceholder = "Search...",
      showCount = true,
      compact = false,
      className,
      ...rest
    },
    ref,
  ) => {
    const [openFilter, setOpenFilter] = useState<string | null>(null);
    const dropdownRef = useRef<HTMLDivElement>(null);

    // Close dropdown on outside click
    useEffect(() => {
      const handleClickOutside = (e: MouseEvent) => {
        if (
          dropdownRef.current &&
          !dropdownRef.current.contains(e.target as Node)
        ) {
          setOpenFilter(null);
        }
      };

      document.addEventListener("mousedown", handleClickOutside);
      return () =>
        document.removeEventListener("mousedown", handleClickOutside);
    }, []);

    const handleFilterSelect = (key: string, value: string | string[]) => {
      onFilterChange(key, value);
    };

    const classNames = [styles.filterBar, compact && styles.compact, className]
      .filter(Boolean)
      .join(" ");

    return (
      <div ref={ref} className={classNames} {...rest}>
        {/* Search */}
        {searchable && (
          <div className={styles.searchWrapper}>
            <Search size={16} className={styles.searchIcon} />
            <input
              type="text"
              className={styles.searchInput}
              placeholder={searchPlaceholder}
              value={searchValue}
              onChange={(e) => onSearchChange?.(e.target.value)}
            />
          </div>
        )}

        {/* Filter triggers */}
        <div className={styles.filters} ref={dropdownRef}>
          {filters.map((filter) => {
            const isActive = activeFilters.some((af) => af.key === filter.key);
            const isOpen = openFilter === filter.key;

            return (
              <div key={filter.key} className={styles.filterWrapper}>
                <button
                  type="button"
                  className={`${styles.filterTrigger} ${isActive ? styles.filterActive : ""}`}
                  onClick={() => setOpenFilter(isOpen ? null : filter.key)}
                >
                  {filter.icon ||
                    (filter.type.includes("date") ? (
                      <Calendar size={14} />
                    ) : (
                      <Filter size={14} />
                    ))}
                  <span>{filter.label}</span>
                  <ChevronDown
                    size={14}
                    className={`${styles.chevron} ${isOpen ? styles.chevronOpen : ""}`}
                  />
                </button>

                {isOpen && filter.type !== "text" && (
                  <FilterDropdown
                    filter={filter}
                    onSelect={(value) => handleFilterSelect(filter.key, value)}
                    onClose={() => setOpenFilter(null)}
                  />
                )}
              </div>
            );
          })}
        </div>

        {/* Active filter chips */}
        {activeFilters.length > 0 && (
          <div className={styles.activeFilters}>
            {activeFilters.map((af) => (
              <span key={af.key} className={styles.chip}>
                <span className={styles.chipLabel}>{af.label}</span>
                <button
                  type="button"
                  className={styles.chipRemove}
                  onClick={() => onFilterRemove(af.key)}
                  aria-label={`Remove ${af.label} filter`}
                >
                  <X size={12} />
                </button>
              </span>
            ))}
            {onClearAll && activeFilters.length > 1 && (
              <button
                type="button"
                className={styles.clearAll}
                onClick={onClearAll}
              >
                Clear all
              </button>
            )}
          </div>
        )}

        {/* Filter count */}
        {showCount && activeFilters.length > 0 && (
          <span className={styles.count}>
            {activeFilters.length} filter{activeFilters.length !== 1 ? "s" : ""}{" "}
            active
          </span>
        )}
      </div>
    );
  },
);

FilterBar.displayName = "FilterBar";

/**
 * FilterBar Component Types
 *
 * Type definitions for the Orion FilterBar section component.
 * Horizontal filter controls with chips for SaaS dashboards.
 */

import type { HTMLAttributes, ReactNode } from "react";

/**
 * Filter option for select/multi-select filters
 */
export interface FilterOption {
  /**
   * Option value
   */
  value: string;

  /**
   * Display label
   */
  label: string;

  /**
   * Optional count
   */
  count?: number;
}

/**
 * Filter definition
 */
export interface FilterDefinition {
  /**
   * Unique filter key
   */
  key: string;

  /**
   * Filter label
   */
  label: string;

  /**
   * Filter type
   */
  type: "select" | "multi-select" | "date" | "date-range" | "text";

  /**
   * Options for select types
   */
  options?: FilterOption[];

  /**
   * Placeholder text
   */
  placeholder?: string;

  /**
   * Icon for the filter
   */
  icon?: ReactNode;
}

/**
 * Active filter value
 */
export interface ActiveFilter {
  /**
   * Filter key
   */
  key: string;

  /**
   * Filter value (or array for multi-select)
   */
  value: string | string[] | { start: string; end: string };

  /**
   * Display label for the chip
   */
  label: string;
}

/**
 * FilterBar section props
 *
 * @example
 * ```tsx
 * <FilterBar
 *   filters={[
 *     { key: 'status', label: 'Status', type: 'select', options: [...] },
 *     { key: 'date', label: 'Date', type: 'date-range' }
 *   ]}
 *   activeFilters={[
 *     { key: 'status', value: 'active', label: 'Active' }
 *   ]}
 *   onFilterChange={(key, value) => updateFilters(key, value)}
 *   onFilterRemove={(key) => removeFilter(key)}
 * />
 * ```
 */
export interface FilterBarProps extends HTMLAttributes<HTMLDivElement> {
  /**
   * Filter definitions
   */
  filters: FilterDefinition[];

  /**
   * Currently active filters
   */
  activeFilters: ActiveFilter[];

  /**
   * Filter change handler
   */
  onFilterChange: (
    key: string,
    value: string | string[] | { start: string; end: string } | null,
  ) => void;

  /**
   * Remove filter handler
   */
  onFilterRemove: (key: string) => void;

  /**
   * Clear all filters handler
   */
  onClearAll?: () => void;

  /**
   * Enable search input
   * @default false
   */
  searchable?: boolean;

  /**
   * Search value (controlled)
   */
  searchValue?: string;

  /**
   * Search change handler
   */
  onSearchChange?: (value: string) => void;

  /**
   * Search placeholder
   */
  searchPlaceholder?: string;

  /**
   * Show filter count
   * @default true
   */
  showCount?: boolean;

  /**
   * Compact mode
   * @default false
   */
  compact?: boolean;
}

/**
 * FilterBar Component Styles
 *
 * Optimized for Product Mode (SaaS dashboards).
 * Horizontal filter controls with clear visual hierarchy.
 */

.filterBar {
  display: flex;
  align-items: center;
  gap: var(--spacing-3);
  padding: var(--spacing-3) var(--spacing-4);
  background: var(--surface-base);
  border: 1px solid var(--border-subtle);
  border-radius: var(--radius-control);
  flex-wrap: wrap;
}

.compact {
  padding: var(--spacing-2) var(--spacing-3);
  gap: var(--spacing-2);
}

/* ============================================================================
 * SEARCH
 * ============================================================================ */

.searchWrapper {
  position: relative;
  display: flex;
  align-items: center;
}

.searchIcon {
  position: absolute;
  left: var(--spacing-2-5);
  color: var(--text-tertiary);
  pointer-events: none;
}

.searchInput {
  padding: var(--spacing-2) var(--spacing-3) var(--spacing-2) var(--spacing-8);
  font-family: var(--font-secondary);
  font-size: var(--font-size-13);
  color: var(--text-primary);
  background: var(--surface-subtle);
  border: 1px solid transparent;
  border-radius: var(--radius-sm);
  width: 200px;
  transition:
    border-color var(--mode-hover-duration),
    background-color var(--mode-hover-duration);
}

.searchInput:focus {
  outline: none;
  background: var(--surface-base);
  border-color: var(--interactive-primary);
}

.searchInput::placeholder {
  color: var(--text-tertiary);
}

/* ============================================================================
 * FILTERS
 * ============================================================================ */

.filters {
  display: flex;
  align-items: center;
  gap: var(--spacing-2);
}

.filterWrapper {
  position: relative;
}

.filterTrigger {
  display: inline-flex;
  align-items: center;
  gap: var(--spacing-1-5);
  padding: var(--spacing-2) var(--spacing-3);
  font-family: var(--font-secondary);
  font-size: var(--font-size-13);
  font-weight: var(--font-weight-medium);
  color: var(--text-secondary);
  background: var(--surface-subtle);
  border: 1px solid transparent;
  border-radius: var(--radius-sm);
  cursor: pointer;
  transition: all var(--mode-hover-duration);
}

.filterTrigger:hover {
  color: var(--text-primary);
  background: var(--surface-layer);
}

.filterActive {
  color: var(--interactive-primary);
  background: var(--status-info-bg);
  border-color: var(--interactive-primary);
}

.chevron {
  transition: transform var(--mode-hover-duration);
}

.chevronOpen {
  transform: rotate(180deg);
}

/* ============================================================================
 * DROPDOWN
 * ============================================================================ */

.dropdown {
  position: absolute;
  top: calc(100% + var(--spacing-1));
  left: 0;
  min-width: 200px;
  max-height: 300px;
  overflow-y: auto;
  background: var(--surface-base);
  border: 1px solid var(--border-subtle);
  border-radius: var(--radius-sm);
  box-shadow: var(--shadow-lg);
  z-index: var(--z-dropdown);
  padding: var(--spacing-1);
}

.dropdownItem {
  display: flex;
  align-items: center;
  gap: var(--spacing-2);
  width: 100%;
  padding: var(--spacing-2) var(--spacing-3);
  font-family: var(--font-secondary);
  font-size: var(--font-size-13);
  color: var(--text-primary);
  background: none;
  border: none;
  border-radius: var(--radius-sm);
  cursor: pointer;
  text-align: left;
  transition: background-color var(--mode-hover-duration);
}

.dropdownItem:hover {
  background: var(--surface-subtle);
}

.dropdownItemSelected {
  background: var(--status-info-bg);
  color: var(--interactive-primary);
}

.checkbox {
  width: 16px;
  height: 16px;
  display: flex;
  align-items: center;
  justify-content: center;
  border: 1px solid var(--border-moderate);
  border-radius: var(--radius-sm);
  font-size: var(--font-size-10);
  flex-shrink: 0;
}

.dropdownItemSelected .checkbox {
  background: var(--interactive-primary);
  border-color: var(--interactive-primary);
  color: var(--interactive-primary-text);
}

.optionCount {
  margin-left: auto;
  font-size: var(--font-size-11);
  color: var(--text-tertiary);
}

.dropdownFooter {
  display: flex;
  justify-content: flex-end;
  gap: var(--spacing-2);
  padding: var(--spacing-2);
  border-top: 1px solid var(--border-subtle);
  margin-top: var(--spacing-1);
}

.dropdownCancel,
.dropdownApply {
  padding: var(--spacing-1-5) var(--spacing-3);
  font-family: var(--font-secondary);
  font-size: var(--font-size-12);
  font-weight: var(--font-weight-medium);
  border-radius: var(--radius-sm);
  cursor: pointer;
  transition: all var(--mode-hover-duration);
}

.dropdownCancel {
  color: var(--text-secondary);
  background: none;
  border: none;
}

.dropdownCancel:hover {
  color: var(--text-primary);
}

.dropdownApply {
  color: var(--interactive-primary-text);
  background: var(--interactive-primary);
  border: none;
}

.dropdownApply:hover {
  background: var(--interactive-primary-hover);
}

/* ============================================================================
 * ACTIVE FILTERS (CHIPS)
 * ============================================================================ */

.activeFilters {
  display: flex;
  align-items: center;
  gap: var(--spacing-2);
  flex-wrap: wrap;
  padding-left: var(--spacing-2);
  border-left: 1px solid var(--border-subtle);
  margin-left: var(--spacing-1);
}

.chip {
  display: inline-flex;
  align-items: center;
  gap: var(--spacing-1);
  padding: var(--spacing-1) var(--spacing-2);
  font-family: var(--font-secondary);
  font-size: var(--font-size-12);
  font-weight: var(--font-weight-medium);
  color: var(--text-primary);
  background: var(--surface-subtle);
  border-radius: var(--radius-full);
}

.chipLabel {
  max-width: 150px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.chipRemove {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 16px;
  height: 16px;
  background: none;
  border: none;
  border-radius: var(--radius-full);
  cursor: pointer;
  color: var(--text-tertiary);
  transition: all var(--mode-hover-duration);
}

.chipRemove:hover {
  background: var(--surface-layer);
  color: var(--text-primary);
}

.clearAll {
  font-family: var(--font-secondary);
  font-size: var(--font-size-12);
  font-weight: var(--font-weight-medium);
  color: var(--text-secondary);
  background: none;
  border: none;
  cursor: pointer;
  text-decoration: underline;
  transition: color var(--mode-hover-duration);
}

.clearAll:hover {
  color: var(--text-error);
}

/* ============================================================================
 * COUNT
 * ============================================================================ */

.count {
  font-family: var(--font-secondary);
  font-size: var(--font-size-12);
  color: var(--text-tertiary);
  margin-left: auto;
}

/* ============================================================================
 * RESPONSIVE
 * ============================================================================ */

@media (max-width: 768px) {
  .filterBar {
    flex-direction: column;
    align-items: stretch;
  }

  .searchWrapper {
    width: 100%;
  }

  .searchInput {
    width: 100%;
  }

  .filters {
    flex-wrap: wrap;
  }

  .activeFilters {
    border-left: none;
    padding-left: 0;
    margin-left: 0;
    padding-top: var(--spacing-2);
    border-top: 1px solid var(--border-subtle);
  }

  .count {
    margin-left: 0;
    margin-top: var(--spacing-2);
  }
}

export { FilterBar } from "./FilterBar";
export type {
  FilterBarProps,
  FilterDefinition,
  FilterOption,
  ActiveFilter,
} from "./FilterBar.types";
